function ParseJSON(dataJSON) {
    const timeDirty = dataJSON.timestamp;
    const intensity = dataJSON.value;

    const time = Temporal.PlainDateTime.from(timeDirty);
    const timeLocale = time.toLocaleString();

    lastDate = time;
    currentDay = time.day;

    let data = new DataEntry(timeLocale, intensity);

    return data;
}

function ParseJSONUTC(dataJSON) {
    const timeDirty = dataJSON.timestamp;
    const intensity = dataJSON.value;

    const time = Temporal.ZonedDateTime.from(timeDirty + "[Europe/Copenhagen]");
    const timeLocale = time.toLocaleString();

    lastDate = time;
    currentDay = time.day;

    let data = new DataEntry(timeLocale, intensity);

    return data;
}

function SetUpGraph(data) {
    if (currentChart !== null) {
        currentChart.destroy();
    }

    currentChart = new Chart(
        document.getElementById("testGraph"), {
            type: "line",
            data: {
                labels: data.map(row => row.Time),
                datasets: [
                    {
                        label: "Lysstyrke",
                        data: data.map(row => row.Intensity)
                    }
                ]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false
            }
        }
    );
}

function SetUpTable(num) {
    const tableDiv = document.getElementById("testTableDiv");
    let dataArray = [];

    if (tableDiv.children.length !== 0) {
        tableDiv.removeChild(tableDiv.firstChild);
    }

    const table = document.createElement("table");
    table.className = "Table";
    table.id = "testTable";
    
    const hRow = document.createElement("tr");

    const hTime = document.createElement("th");
    hTime.innerText = "Tid";
    hTime.className = "TableDataTop";
    hRow.appendChild(hTime);
    
    const hData = document.createElement("th");
    hData.innerText = "Lysintensitet";
    hData.className = "TableDataTop";
    hRow.appendChild(hData);

    table.appendChild(hRow);

    PopulateTable(table, dataArray, num);

    // Skal flyttes senere
    SetUpGraph(dataArray);

    tableDiv.appendChild(table);
}

function SetUpTableReal(data) {
    const tableDiv = document.getElementById("testTableDiv");
    let dataArray = [];

    if (tableDiv.children.length !== 0) {
        tableDiv.removeChild(tableDiv.firstChild);
    }

    const table = document.createElement("table");
    table.className = "Table";
    table.id = "testTable";
    
    const hRow = document.createElement("tr");

    const hTime = document.createElement("th");
    hTime.innerText = "Tid";
    hTime.className = "TableDataTop";
    hRow.appendChild(hTime);
    
    const hData = document.createElement("th");
    hData.innerText = "Lysintensitet";
    hData.className = "TableDataTop";
    hRow.appendChild(hData);

    table.appendChild(hRow);

    PopulateTableReal(table, dataArray, data);

    // Skal flyttes senere
    SetUpGraph(data);

    tableDiv.appendChild(table);
}

// Bruges kun til testdata
function PopulateTable(table, dataArray, num) {
    let dataTable;

    switch (num) {
        case 0:
            dataTable = dataOneHour;
            break;

        case 1:
            dataTable = dataSixHours;
            break;

        case 2:
            dataTable = dataOneDay;
            break;

        case 3:
            dataTable = dataThreeDays;
            break;

        case 4:
            dataTable = dataOneWeek;
            break;

        case 5:
            dataTable = dataOneMonth;
            break;
    
        default:
            break;
    }

    for (let i = 0; i < dataTable.length; i++) {
        const data = ParseJSONUTC(dataTable[i]);
        dataArray.push(data);

        if (i === 0 || currentDay !== lastDay) {
            const row = document.createElement("tr");
            row.className = "TablePatternBreaker";
            
            const hDate = document.createElement("th");
            hDate.setAttribute("colspan", "2");
            hDate.className = "TableDateHeader";
            const dateString = data.Time.substring(0, 10);
            hDate.innerText = dateString;
            row.appendChild(hDate);

            table.appendChild(row);

            if (i === 0) {
                lastDay = currentDay;
            }
        }
        
        const row = document.createElement("tr");

        const time = document.createElement("td");
        const timeString = data.Time.substring(12);
        time.innerText = timeString;
        row.appendChild(time);

        const intensity = document.createElement("td");
        intensity.innerText = data.Intensity;
        row.appendChild(intensity);

        table.appendChild(row);

        lastDay = currentDay;
    }
}

function PopulateTableReal(table, dataArray, data) {
    for (let i = 0; i < data.length; i++) {
        const newData = ParseJSONUTC(data[i]);
        dataArray.push(newData);

        if (i === 0 || currentDay !== lastDay) {
            const row = document.createElement("tr");
            row.className = "TablePatternBreaker";
            
            const hDate = document.createElement("th");
            hDate.setAttribute("colspan", "2");
            hDate.className = "TableDateHeader";
            const dateString = newData.Time.substring(0, 10);
            hDate.innerText = dateString;
            row.appendChild(hDate);

            table.appendChild(row);

            if (i === 0) {
                lastDay = currentDay;
            }
        }
        
        const row = document.createElement("tr");

        const time = document.createElement("td");
        const timeString = newData.Time.substring(12);
        time.innerText = timeString;
        row.appendChild(time);

        const intensity = document.createElement("td");
        intensity.innerText = newData.Intensity;
        row.appendChild(intensity);

        table.appendChild(row);

        lastDay = currentDay;
    }
}

function NowPressed() {
    const temp = Temporal.Now.instant();
    const time = temp.toZonedDateTimeISO("Europe/Copenhagen");

    const dateInput = document.getElementById("dateInput");
    const timeInputHour = document.getElementById("timeInputHour");
    const timeInputMinute = document.getElementById("timeInputMinute");

    let dayString = "";
    if (10 > Number(time.day)) {
        dayString = "0";
    }
    dayString += String(time.day);

    let monthString = "";
    if (10 > Number(time.month)) {
        monthString = "0";
    }
    monthString += String(time.month);

    const dateString = String(time.year) + "-" + String(monthString) + "-" + String(dayString);

    dateInput.value = dateString;
    timeInputHour.value = String(time.hour);
    timeInputMinute.value = String(time.minute);
}

async function TestFetch() {
    const requestOptions = {
        method: "GET",
        redirect: "follow"
    };
    
    fetch("http://10.133.51.104:8080/api/measurement", requestOptions)
        .then((response) => response.text())
        .then((result) => SetUpTableReal(JSON.parse(result)))
        //.then((result) => console.log(result))
        .catch((error) => console.error(error));
}

window.onload = NowPressed;
